import { klona } from 'klona';
import { Schema as MvuSchema } from '../修仙状态栏/schema';
import { deriveMaxHp, deriveMaxMp } from '../修仙状态栏/vitals';
import { 当前设定版本, 世界引擎Schema, 种子世界状态 } from './schema';
const 轮回变量键 = '黑色修士.轮回档案';
const 周目内容上限 = 600;
const 周目结局上限 = 120;
const 人物志上限 = 150;
const 继承方式Schema = z.enum(['前世回响', '轮回同行', '神契随行']);
export const 轮回人物Schema = z
    .object({
    名称: z.string().prefault(''),
    类型: z.enum(['羁绊', '重要人物', '古神']).prefault('羁绊'),
    继承方式: 继承方式Schema.prefault('前世回响'),
    人物志: z
        .string()
        .transform(value => 规范文本(value, 人物志上限))
        .prefault(''),
})
    .prefault({});
export const 周目档案Schema = z
    .object({
    编号: z.coerce
        .number()
        .transform(value => Math.max(1, Math.trunc(value)))
        .prefault(1),
    标题: z
        .string()
        .transform(value => 规范文本(value, 24))
        .prefault('无题轮回'),
    内容: z
        .string()
        .transform(value => 规范文本(value, 周目内容上限))
        .prefault(''),
    结局: z
        .string()
        .transform(value => 规范文本(value, 周目结局上限))
        .prefault(''),
    完成时间: z.coerce.number().prefault(() => Date.now()),
    人物志: z.record(z.string().describe('人物名'), 轮回人物Schema).prefault({}),
    MVU继承快照: z.unknown().prefault({}),
})
    .prefault({});
export const 角色轮回档案Schema = z
    .object({
    版本: z.coerce.number().prefault(1),
    最新完成周目: z.coerce
        .number()
        .transform(value => Math.max(0, Math.trunc(value)))
        .prefault(0),
    待继承周目: z.coerce
        .number()
        .transform(value => Math.max(0, Math.trunc(value)))
        .prefault(0),
    档案: z.record(z.string().describe('周目编号'), 周目档案Schema).prefault({}),
})
    .prefault({});
function 规范文本(value, max) {
    return String(value ?? '')
        .replace(/^```(?:json|text|markdown)?\s*/i, '')
        .replace(/```\s*$/i, '')
        .replace(/\s+/g, ' ')
        .trim()
        .slice(0, max);
}
function 安全数字(value) {
    const number = Number(value);
    return Number.isFinite(number) ? number : 0;
}
/** 跨聊天读取当前角色卡的历代周目档案。 */
export function 读取角色轮回档案() {
    try {
        const variables = getVariables({ type: 'character' });
        return 角色轮回档案Schema.parse(_.get(variables, 轮回变量键, {}));
    }
    catch (error) {
        console.warn('[世界引擎] 读取角色轮回档案失败', error);
        return 角色轮回档案Schema.parse({});
    }
}
function 写入角色轮回档案(data) {
    const variables = getVariables({ type: 'character' });
    _.set(variables, 轮回变量键, klona(角色轮回档案Schema.parse(data)));
    replaceVariables(variables, { type: 'character' });
}
export function 读取待继承周目() {
    const data = 读取角色轮回档案();
    if (!data.待继承周目)
        return null;
    return data.档案[String(data.待继承周目)] ?? null;
}
export function 消费待继承周目(编号) {
    const data = 读取角色轮回档案();
    if (data.待继承周目 !== 编号)
        return;
    data.待继承周目 = 0;
    写入角色轮回档案(data);
}
export function 保存周目档案(entry) {
    const normalized = 周目档案Schema.parse(entry);
    const data = 读取角色轮回档案();
    data.档案[String(normalized.编号)] = normalized;
    data.最新完成周目 = Math.max(data.最新完成周目, normalized.编号);
    data.待继承周目 = normalized.编号;
    写入角色轮回档案(data);
    return normalized;
}
/** 从最新 MVU 中筛选真正建立过关系或已经收服的轮回人物候选。 */
export function 读取轮回人物候选() {
    try {
        const variables = getVariables({ type: 'message', message_id: -1 });
        const stat = MvuSchema.parse(_.get(variables, 'stat_data', {}));
        const result = new Map();
        for (const [名称, person] of Object.entries(stat.羁绊)) {
            const important = stat.重要人物[名称];
            const god = stat.古神列表[名称];
            const 类型 = god?.收服 ? '古神' : important ? '重要人物' : '羁绊';
            result.set(名称, {
                名称,
                类型,
                继承方式: god?.收服 ? '神契随行' : important ? '前世回响' : '轮回同行',
                关系: person.关系,
                好感度: person.好感度,
                身份: [important?.称号, person.境界, person.势力].filter(Boolean).join(' · '),
                摘要: person.描述 || important?.描述 || '',
            });
        }
        for (const [名称, person] of Object.entries(stat.重要人物)) {
            const 有关系 = person.攻略 || person.好感度 !== 0 || !['', '中立', '陌路人'].includes(person.关系);
            if (!有关系 || result.has(名称))
                continue;
            result.set(名称, {
                名称,
                类型: '重要人物',
                继承方式: '前世回响',
                关系: person.关系,
                好感度: person.好感度,
                身份: [person.称号, person.境界, person.势力].filter(Boolean).join(' · '),
                摘要: person.描述,
            });
        }
        for (const [名称, god] of Object.entries(stat.古神列表)) {
            if (!god.收服 || result.has(名称))
                continue;
            result.set(名称, {
                名称,
                类型: '古神',
                继承方式: '神契随行',
                关系: '神契同行',
                好感度: stat.羁绊[名称]?.好感度 ?? 50,
                身份: [god.位阶, god.神格, god.领域].filter(Boolean).join(' · '),
                摘要: god.描述,
            });
        }
        return [...result.values()].sort((a, b) => b.好感度 - a.好感度 || a.名称.localeCompare(b.名称));
    }
    catch (error) {
        console.warn('[世界引擎] 读取轮回人物候选失败', error);
        return [];
    }
}
/** 只保存可跨周目的稳定人物成长；世界、在场和秘境等瞬时状态不进入快照。 */
export function 构建MVU继承快照(人物志) {
    const variables = getVariables({ type: 'message', message_id: -1 });
    const stat = MvuSchema.parse(_.get(variables, 'stat_data', {}));
    const names = new Set(Object.keys(人物志));
    const 主角 = klona(stat.主角);
    if (主角.神契装备 && !names.has(主角.神契装备))
        主角.神契装备 = '';
    const 羁绊 = klona(_.pick(stat.羁绊, [...names]));
    for (const name of names) {
        if (羁绊[name])
            continue;
        const important = stat.重要人物[name];
        const god = stat.古神列表[name];
        if (important) {
            羁绊[name] = {
                气血: deriveMaxHp(important._属性),
                法力值: deriveMaxMp(important._属性),
                善恶值: 0,
                san值: 80,
                好感度: important.好感度,
                洗脑值: important.洗脑值,
                内心想法: '',
                境界: important.境界,
                种族: '人族',
                性别: '未知',
                势力: important.势力,
                描述: important.描述,
                外貌: important.外貌,
                关系: important.关系,
                六维: klona(important._属性),
            };
        }
        else if (god) {
            羁绊[name] = {
                气血: 100,
                法力值: 100,
                善恶值: 0,
                san值: 100,
                好感度: 50,
                洗脑值: 0,
                内心想法: '',
                境界: god.位阶,
                种族: '古神',
                性别: '未知',
                势力: '古神',
                描述: god.描述,
                外貌: '',
                关系: '神契同行',
                六维: { 力道: 0, 体魄: 0, 身法: 0, 灵力: 0, 神识: 0, 根骨: 0 },
            };
        }
    }
    return {
        主角,
        功法: klona(stat.功法),
        初始功法: klona(stat.初始功法),
        羁绊: MvuSchema.shape.羁绊.parse(羁绊),
        重要人物: klona(_.pick(stat.重要人物, [...names])),
        古神列表: klona(_.pickBy(stat.古神列表, (_value, name) => names.has(name))),
        爱室: klona(_.pick(stat.爱室, [...names])),
        永久标志: {
            拥有黑之匙: stat.$flag.拥有黑之匙,
            主角属性无上限: stat.$flag.主角属性无上限,
            已结算功法属性: [...stat.$flag.已结算功法属性],
        },
    };
}
/** 把档案快照覆盖到新聊天 initvar 上，同时重置本周目的时空与临时状态。 */
export function 应用轮回继承(current, entry) {
    const base = MvuSchema.parse(current);
    const snapshot = (entry.MVU继承快照 ?? {});
    const 一周目初始羁绊 = klona(base.羁绊);
    const 一周目初始在场 = klona(base.在场);
    const 一周目初始神契 = base.主角.神契装备;
    if (snapshot.主角)
        base.主角 = MvuSchema.shape.主角.parse(snapshot.主角);
    if (!base.主角.神契装备 && 一周目初始神契)
        base.主角.神契装备 = 一周目初始神契;
    base.主角.状态 = '正常';
    base.主角.气血 = deriveMaxHp(base.主角.六维);
    base.主角.法力值 = deriveMaxMp(base.主角.六维);
    base.功法 = MvuSchema.shape.功法.parse(snapshot.功法 ?? {});
    base.初始功法 = MvuSchema.shape.初始功法.parse(snapshot.初始功法 ?? {});
    base.羁绊 = MvuSchema.shape.羁绊.parse({
        ...一周目初始羁绊,
        ...(snapshot.羁绊 ?? {}),
    });
    base.重要人物 = MvuSchema.shape.重要人物.parse({
        ...base.重要人物,
        ...(snapshot.重要人物 ?? {}),
    });
    base.古神列表 = MvuSchema.shape.古神列表.parse({
        ...base.古神列表,
        ...(snapshot.古神列表 ?? {}),
    });
    base.爱室 = MvuSchema.shape.爱室.parse(snapshot.爱室 ?? {});
    base.世界 = {
        当前年号: '太初',
        当前时间: '混沌历元年·卯初',
        当前地点: '中州东部·东平州边境·七国驿道旁临时营地',
        当前坐标: { x: 60.46, y: 56.17 },
    };
    base.在场 = MvuSchema.shape.在场.parse(一周目初始在场);
    base.当前秘境 = MvuSchema.shape.当前秘境.parse({});
    base.$flag = {
        游戏模式: '剧情模式',
        已完成捏角: false,
        已注入变量: false,
        主角属性无上限: snapshot.永久标志?.主角属性无上限 !== false,
        已结算功法属性: Array.isArray(snapshot.永久标志?.已结算功法属性)
            ? snapshot.永久标志.已结算功法属性.filter((name) => typeof name === 'string')
            : [],
        拥有黑之匙: Boolean(snapshot.永久标志?.拥有黑之匙),
        开场功法豁免: [],
        剧情结局: {
            首位满好感角色: '',
            当前结局: '未触发',
            个人线角色: '',
            触发时间: '',
            推进轮数: 0,
            周目提示状态: '未提示',
        },
    };
    for (const [name, person] of Object.entries(entry.人物志)) {
        if (!base.羁绊[name])
            continue;
        base.羁绊[name].内心想法 = `${base.羁绊[name].内心想法}；轮回人物志：${person.人物志}`.replace(/^；/, '');
        if (person.继承方式 === '轮回同行' || person.继承方式 === '神契随行') {
            base.在场[name] = klona(base.羁绊[name]);
        }
    }
    return MvuSchema.parse(base);
}
/** 新聊天接受继承后，为世界引擎建立对应的第 N+1 周目进度。 */
export function 标记当前聊天继承(entry) {
    const variables = getVariables({ type: 'chat' });
    const raw = _.get(variables, '世界引擎');
    const engine = 世界引擎Schema.parse(raw ?? { 设定版本: 当前设定版本, 世界状态: 种子世界状态 });
    engine.周目 = {
        编号: entry.编号 + 1,
        来源周目: entry.编号,
        状态: '进行中',
        继承已应用: true,
        经历: {},
        上次经历楼层: getLastMessageId(),
    };
    engine.摘要 = { 近期摘要: '', 上次摘要楼层: getLastMessageId() };
    _.set(variables, '世界引擎', engine);
    replaceVariables(variables, { type: 'chat' });
}
export function 构建轮回开场提示(entry) {
    const next = entry.编号 + 1;
    const people = Object.values(entry.人物志);
    const peopleText = people.length
        ? `与<user>一同跨越轮回的角色有：${people.map(person => `${person.名称}（${person.继承方式}）`).join('、')}。`
        : '没有其他角色与<user>一同跨越轮回。';
    return `<start>\n【第${next}周目开场】\n<user>再度苏醒，带着第${entry.编号}周目的完整回忆，回到了第一周目开头的场景：中州东平州边境，七国驿道旁的临时营地，时间仍是清晨。胧正在身边叫醒<user>，眼前的一切都与最初那次苏醒相同，但<user>清楚知道自己已经经历过上一世。\n\n${peopleText}除明确跨越轮回的角色外，当前世界中的其他人物并不知道上一世发生过什么，上一世的事件也尚未在这一周目发生。\n\n从<user>睁眼看见胧的瞬间开始正文，通过<user>对眼前场景的熟悉与上一世记忆自然表现轮回，不要复述轮回档案，不要将开场写成陌生的新旅程。\n</start>`;
}
export function 格式化轮回记忆(entry) {
    const people = Object.values(entry.人物志);
    const lines = [
        `【轮回认知】<user>明确记得自己已结束第${entry.编号}周目，当前是第${entry.编号 + 1}周目。前世事件未默认发生在本时间线；除下列继承人物外，其他角色默认不知晓前世。`,
        `【前世结局】内容：${entry.内容} 结局：${entry.结局}`,
    ];
    if (people.length) {
        lines.push(`【轮回人物】${people.map(person => `${person.名称}（${person.继承方式}）：${person.人物志}`).join('；')}`);
    }
    return lines.join('\n');
}
export function 规范周目标题(value) {
    return 规范文本(value, 24) || '无题轮回';
}
export function 规范周目内容(value) {
    return 规范文本(value, 周目内容上限);
}
export function 规范周目结局(value) {
    return 规范文本(value, 周目结局上限);
}
export function 规范人物志(value) {
    return 规范文本(value, 人物志上限);
}
export function 候选好感度(value) {
    return _.clamp(安全数字(value), -100, 100);
}
