export interface MapPoint {
  x: number;
  y: number;
}

export const WORLD_MAP_IMAGE_URL =
  'https://cdn.jsdelivr.net/gh/roikoni/my_blog_image/A%3A%5CSilly%20Tavern%E7%9B%B8%E5%85%B3%5C%E5%9B%BE%E5%BA%8A-%E6%88%91%E8%A2%AB%E7%8C%AB%E5%A8%98%E5%8C%85%E5%9B%B4%E4%BA%86!%E6%AD%A3%E5%BC%8F%E5%9C%B0%E5%9B%BE%E7%AC%AC%E4%B8%80%E7%89%88.jpeg';

export interface FixedMapLocation extends MapPoint {
  name: string;
  aliases: string[];
  region: string;
  type: string;
  color?: string;
  description?: string;
}

export interface FixedMapRegion extends MapPoint {
  name: string;
  aliases: string[];
}

export interface FixedMapData {
  version: number;
  defaultCenter: MapPoint;
  regions: FixedMapRegion[];
  locations: FixedMapLocation[];
}

export interface MapPolygonRegion {
  势力: string;
  颜色: string;
  透明度: number;
  描述: string;
  顶点: MapPoint[];
}

export interface MapRegionMatch extends MapPolygonRegion {
  name: string;
}

export type MapMatchSource = 'mvu-coordinate' | 'fixed-exact' | 'fixed-alias' | 'region' | 'default';

export interface MapLocationMatch extends MapPoint {
  name: string;
  source: MapMatchSource;
}

function normalize(value: string): string {
  return value.trim().replace(/\s+/g, '').toLocaleLowerCase();
}

function phraseMatches(place: string, phrase: string): boolean {
  const target = normalize(phrase);
  if (!target) return false;

  const normalizedPlace = normalize(place);
  if (normalizedPlace === target) return true;

  const segments = place
    .split(/[·•/／、,，>＞—–-]+/)
    .map(normalize)
    .filter(Boolean);
  return segments.includes(target);
}

function longestMatch<T>(items: T[], terms: (item: T) => string[], place: string): T | undefined {
  return items
    .map(item => ({ item, length: Math.max(0, ...terms(item).filter(term => phraseMatches(place, term)).map(term => normalize(term).length)) }))
    .filter(candidate => candidate.length > 0)
    .sort((a, b) => b.length - a.length)[0]?.item;
}

export function resolveMapLocation(
  place: string,
  fixedData: FixedMapData,
): MapLocationMatch {
  const exact = longestMatch(fixedData.locations, item => [item.name], place);
  if (exact) return { name: exact.name, x: exact.x, y: exact.y, source: 'fixed-exact' };

  const alias = longestMatch(fixedData.locations, item => item.aliases, place);
  if (alias) return { name: alias.name, x: alias.x, y: alias.y, source: 'fixed-alias' };

  const region = longestMatch(fixedData.regions, item => [item.name, ...item.aliases], place);
  if (region) return { name: region.name, x: region.x, y: region.y, source: 'region' };

  return { name: place || '未知之地', ...fixedData.defaultCenter, source: 'default' };
}

export function hasValidMapCoordinates(value: unknown): value is MapPoint {
  if (!value || typeof value !== 'object') return false;
  const point = value as Partial<MapPoint>;
  return Number.isFinite(point.x) && Number.isFinite(point.y)
    && Number(point.x) >= 0 && Number(point.x) <= 100
    && Number(point.y) >= 0 && Number(point.y) <= 100;
}

/** MVU 精确坐标优先；旧存档没有坐标时才按地点名匹配静态地图。 */
export function resolveCurrentMapLocation(
  place: string,
  coordinates: unknown,
  fixedData: FixedMapData,
): MapLocationMatch {
  if (hasValidMapCoordinates(coordinates)) {
    return {
      name: place || '未知之地',
      x: Number(coordinates.x),
      y: Number(coordinates.y),
      source: 'mvu-coordinate',
    };
  }
  return resolveMapLocation(place, fixedData);
}

function polygonArea(vertices: MapPoint[]): number {
  if (vertices.length < 3) return Number.POSITIVE_INFINITY;
  return Math.abs(vertices.reduce((sum, point, index) => {
    const next = vertices[(index + 1) % vertices.length];
    return sum + point.x * next.y - next.x * point.y;
  }, 0) / 2);
}

export function isPointInMapRegion(point: MapPoint, vertices: MapPoint[]): boolean {
  if (vertices.length < 3) return false;
  let inside = false;
  for (let i = 0, j = vertices.length - 1; i < vertices.length; j = i++) {
    const a = vertices[i];
    const b = vertices[j];
    const crosses = (a.y > point.y) !== (b.y > point.y)
      && point.x < ((b.x - a.x) * (point.y - a.y)) / (b.y - a.y) + a.x;
    if (crosses) inside = !inside;
  }
  return inside;
}

/** 重叠区域优先返回面积更小的多边形，使城池、宗门等具体范围覆盖大洲区域。 */
export function resolveMapRegionAtPoint(
  point: MapPoint,
  regions: Record<string, MapPolygonRegion>,
): MapRegionMatch | null {
  const matches = Object.entries(regions)
    .filter(([, region]) => isPointInMapRegion(point, region.顶点))
    .sort(([, a], [, b]) => polygonArea(a.顶点) - polygonArea(b.顶点));
  const match = matches[0];
  return match ? { name: match[0], ...match[1] } : null;
}
