export type 道途身份 = '修士' | '非修士';
export type 本源基调 = '正经' | '搞笑' | '涩涩';

export interface 功法生成配置 {
  道途身份: 道途身份;
  本源基调: 本源基调;
}

export const 功法生成配置路径 = '黑色修士.功法生成配置';

const 默认配置: 功法生成配置 = {
  道途身份: '修士',
  本源基调: '正经',
};

function 是道途身份(value: unknown): value is 道途身份 {
  return value === '修士' || value === '非修士';
}

function 是本源基调(value: unknown): value is 本源基调 {
  return value === '正经' || value === '搞笑' || value === '涩涩';
}

/** 从当前聊天读取开场写入的功法生成配置，并允许调用方用显式参数覆盖。 */
export function 读取功法生成配置(overrides: Partial<功法生成配置> = {}): 功法生成配置 {
  const saved = _.get(getVariables({ type: 'chat' }), 功法生成配置路径) as Partial<功法生成配置> | undefined;
  const 道途身份 = 是道途身份(overrides.道途身份)
    ? overrides.道途身份
    : 是道途身份(saved?.道途身份)
      ? saved.道途身份
      : 默认配置.道途身份;
  const 本源基调 = 是本源基调(overrides.本源基调)
    ? overrides.本源基调
    : 是本源基调(saved?.本源基调)
      ? saved.本源基调
      : 默认配置.本源基调;

  return {
    道途身份,
    本源基调,
  };
}

/** 将开场选择写入聊天变量，供后续状态栏里的手动生成继续沿用。 */
export function 写入功法生成配置(config: 功法生成配置): void {
  updateVariablesWith(variables => {
    _.set(variables, 功法生成配置路径, config);
    return variables;
  }, { type: 'chat' });
}
