import { klona } from 'klona';
import { Schema as StatDataSchema, type Schema as StatData } from '../../修仙状态栏/schema';
import { 结算已学习功法属性 } from '../../_shared/techniqueAttributeBonus';
import 剧情模式预设 from '../../黑色修士/世界书/[story_init]剧情模式变量勿开.yaml';

const variableOption = () => ({ type: 'message', message_id: getCurrentMessageId() }) as const;

function expandMacros(value: unknown): unknown {
  if (typeof value === 'string') return substitudeMacros(value);
  if (Array.isArray(value)) return value.map(expandMacros);
  if (_.isPlainObject(value)) return _.mapValues(value as Record<string, unknown>, expandMacros);
  return value;
}

/**
 * 以当前楼层的公共 initvar 为底座，用剧情专属 YAML 替换场景态字段。
 * 固定世界名录只做条目级补丁，避免为了调整胧的开局状态而覆盖其他古神。
 */
export function buildStoryModeData(current: unknown): StatData {
  const base = StatDataSchema.parse(current);
  const preset = expandMacros(剧情模式预设) as Record<string, unknown>;
  const entryPatchKeys = new Set(['古神列表', '旧日支配者列表', '重要人物']);

  for (const [key, value] of Object.entries(preset)) {
    if (entryPatchKeys.has(key)) {
      const currentEntries = _.get(base, [key], {});
      _.set(base, [key], _.merge({}, currentEntries, klona(value)));
    } else {
      _.set(base, [key], klona(value));
    }
  }

  const result = StatDataSchema.parse(base);
  结算已学习功法属性(result);
  return StatDataSchema.parse(result);
}

export function getOpeningMvuSnapshot(): ReturnType<typeof Mvu.getMvuData> {
  return klona(Mvu.getMvuData(variableOption()));
}

/** 完整替换开场界面所在楼层的 stat_data，并等待 MVU 写入结束。 */
export async function replaceOpeningStatData(statData: unknown): Promise<StatData> {
  const parsed = StatDataSchema.parse(statData);
  const mvuData = getOpeningMvuSnapshot();
  _.set(mvuData, 'stat_data', parsed);
  await Mvu.replaceMvuData(mvuData, variableOption());
  return parsed;
}

/** 恢复进入剧情模式前的完整 MVU 变量快照。 */
export async function restoreOpeningMvuSnapshot(snapshot: ReturnType<typeof Mvu.getMvuData>): Promise<StatData> {
  const restored = klona(snapshot);
  await Mvu.replaceMvuData(restored, variableOption());
  return StatDataSchema.parse(_.get(restored, 'stat_data', {}));
}
