export const 六维属性键 = ['力道', '体魄', '身法', '灵力', '神识', '根骨'] as const;

export type 六维属性键 = (typeof 六维属性键)[number];
export type 六维属性加成 = Partial<Record<六维属性键, number>>;

type 功法Like = {
  类型?: unknown;
  效果?: unknown;
  属性加成?: unknown;
  已学习?: unknown;
};

type 功法结算数据Like = {
  主角?: {
    六维?: Partial<Record<六维属性键, unknown>>;
  };
  功法?: Record<string, 功法Like>;
  初始功法?: Record<string, 功法Like>;
  $flag?: {
    游戏模式?: unknown;
    主角属性无上限?: unknown;
    已结算功法属性?: unknown;
  };
};

const 属性正则 = /(力道|体魄|身法|灵力|神识|根骨)\s*([+-])\s*(\d+(?:\.\d+)?)/g;

/** 从“力道+3，神识-1”一类文本中提取六维变化。 */
export function 解析六维属性加成(text: unknown): 六维属性加成 {
  const result: 六维属性加成 = {};
  if (typeof text !== 'string' || !text.trim()) return result;

  属性正则.lastIndex = 0;
  let match: RegExpExecArray | null;
  while ((match = 属性正则.exec(text)) !== null) {
    const key = match[1] as 六维属性键;
    const value = Number(match[3]) * (match[2] === '-' ? -1 : 1);
    if (!Number.isFinite(value) || value === 0) continue;
    result[key] = (result[key] ?? 0) + value;
  }
  return result;
}

/** 将解析后的加成统一为“力道+3，神识-1”格式。 */
export function 格式化六维属性加成(bonus: 六维属性加成): string {
  return 六维属性键
    .filter(key => Number.isFinite(bonus[key]) && bonus[key] !== 0)
    .map(key => `${key}${Number(bonus[key]) > 0 ? '+' : ''}${Number(bonus[key])}`)
    .join('，');
}

/** 优先读取专用字段；旧功法缺少该字段时兼容从效果文本提取。 */
export function 读取功法属性加成(technique: 功法Like): 六维属性加成 {
  const explicit = 解析六维属性加成(technique.属性加成);
  if (Object.keys(explicit).length > 0) return explicit;
  return 解析六维属性加成(technique.效果);
}

/**
 * 将尚未结算的已学习被动功法一次性写入主角真实六维。
 *
 * 初始功法与功法树可能存在同名镜像，因此按功法名去重；已结算名称保存在
 * `$flag.已结算功法属性`，避免刷新、读档和跨周目时重复增加。
 */
export function 结算已学习功法属性(statData: 功法结算数据Like): string[] {
  const 主角六维 = statData.主角?.六维;
  if (!主角六维) return [];

  if (!statData.$flag) statData.$flag = {};
  const 已结算 = new Set(
    Array.isArray(statData.$flag.已结算功法属性)
      ? statData.$flag.已结算功法属性.filter((name): name is string => typeof name === 'string' && name.length > 0)
      : [],
  );
  const 全部功法 = {
    ...(statData.初始功法 ?? {}),
    ...(statData.功法 ?? {}),
  };
  const 无上限 = statData.$flag.游戏模式 === '剧情模式' && statData.$flag.主角属性无上限 === true;
  const 上限 = 无上限 ? Number.POSITIVE_INFINITY : 100;
  const 本次结算: string[] = [];

  for (const [name, technique] of Object.entries(全部功法)) {
    if (已结算.has(name) || technique?.已学习 !== true || technique?.类型 !== '被动') continue;

    const bonus = 读取功法属性加成(technique);
    if (Object.keys(bonus).length === 0) continue;

    for (const key of 六维属性键) {
      const delta = bonus[key];
      if (!Number.isFinite(delta) || delta === 0) continue;
      const current = Number(主角六维[key]);
      const next = (Number.isFinite(current) ? current : 0) + Number(delta);
      主角六维[key] = Math.min(上限, Math.max(0, next));
    }

    if (typeof technique.属性加成 !== 'string' || !technique.属性加成.trim()) {
      technique.属性加成 = 格式化六维属性加成(bonus);
    }
    已结算.add(name);
    本次结算.push(name);
  }

  statData.$flag.已结算功法属性 = [...已结算];
  return 本次结算;
}
