import { 功法列表, type 功法层级 } from '../catalog/功法';
import { 神级功法列表 } from '../catalog/神级功法';
import { 神契列表 } from '../catalog/神契';
import { 层级编号 } from '../../_shared/costTable';
import type { 功法树条目 } from '../../_shared/gongfaTypes';
import { 结算已学习功法属性 } from '../../_shared/techniqueAttributeBonus';
import { deriveMaxHp, deriveMaxMp } from '../../修仙状态栏/vitals';

const 六维键 = ['力道', '体魄', '身法', '灵力', '神识', '根骨'] as const;

/** stat_data 中 初始功法[*] 的条目结构（见 schema.ts） */
interface 初始功法条目 {
  类型: '主动' | '被动';
  层级: number;
  前置功法: string;
  效果: string;
  属性加成: string;
  已学习: boolean;
  消耗灵悟: number;
  描述: string;
}

/**
 * 从功法「效果」文本里正则提取六维加成，拼成属性加成串。
 * 形如"体魄+3""体魄+3，身法+2"，把"力道/体魄/身法/灵力/神识/根骨"后紧跟的 +n 提取出来。
 * 提取不到返回空串（被动加成留空，避免凭空捏造）。
 */
export function extractAttributeBonus(效果: string): string {
  if (!效果) return '';
  const found: string[] = [];
  for (const 键 of 六维键) {
    // 匹配 形如 「体魄+3」「体魄 +3」「神识+5」
    const re = new RegExp(`${键}\\s*\\+\\s*(\\d+)`);
    const m = 效果.match(re);
    if (m) found.push(`${键}+${m[1]}`);
  }
  return found.join('，');
}

/** 把单个功法名拼成 初始功法 条目结构；catalog 找不到则降级为最简条目 */
function buildInitialGongfa(名: string): 初始功法条目 {
  const c = 功法列表.find(g => g.名称 === 名) ?? 神级功法列表.find(g => g.名称 === 名);
  if (c) {
    return {
      类型: c.类型,
      层级: 层级编号[c.层级 as 功法层级 | '神级'] ?? 1,
      前置功法: '',
      效果: c.效果,
      属性加成: extractAttributeBonus(c.效果),
      已学习: true,
      消耗灵悟: 0,
      描述: '',
    };
  }
  return {
    类型: '被动',
    层级: 1,
    前置功法: '',
    效果: '',
    属性加成: '',
    已学习: true,
    消耗灵悟: 0,
    描述: '',
  };
}

/** 据捏角内容构建应注入的 初始功法 表（功法名→条目） */
export function build初始功法(已选功法名: readonly string[]): Record<string, 初始功法条目> {
  const out: Record<string, 初始功法条目> = {};
  for (const 名 of 已选功法名) {
    if (!名) continue;
    out[名] = buildInitialGongfa(名);
  }
  return out;
}

/**
 * 把已选功法镜像写入 stat_data.功法 作为根节点（已学习=true，前置功法=''）。
 * 后续由 generateInitialBranches 在其基础上通过 AI 生成 L+1 级分支。
 */
function seedRootTechniques(stat_data: any, 已选功法: readonly string[]): void {
  if (!stat_data.功法) stat_data.功法 = {};
  for (const 名 of 已选功法) {
    if (!名) continue;
    const c = 功法列表.find(g => g.名称 === 名) ?? 神级功法列表.find(g => g.名称 === 名);
    if (c) {
      stat_data.功法[名] = {
        类型: c.类型,
        层级: 层级编号[c.层级 as 功法层级 | '神级'] ?? 1,
        前置功法: '',
        效果: c.效果,
        属性加成: extractAttributeBonus(c.效果),
        已学习: true,
        消耗灵悟: 0,
        描述: '',
      } as 功法树条目;
    } else {
      stat_data.功法[名] = {
        类型: '被动',
        层级: 1,
        前置功法: '',
        效果: '',
        属性加成: '',
        已学习: true,
        消耗灵悟: 0,
        描述: '',
      } as 功法树条目;
    }
  }
}

/**
 * 把捏角内容预输入到 mvu stat_data（纯前端，不触发 AI）。
 * 这是沙盒模式第一步「注入变量」的核心逻辑：
 *  - 初始功法：据 draft 已选功法拼完整结构（属性加成从效果文本提取），替代原 AI insert
 *  - 功法树根节点：同步 seed 到 stat_data.功法，供后续 AI 分支生成
 *  - 古神列表：以本次捏角选择为准，先关闭所有古神收服，再置 已选神契 对应古神 收服=true
 *  - 神契装备：确保与 已选神契 一致
 *  - 当前地点：使用出身地初始化，供顶部文字与剧情称呼使用
 *  - 当前坐标：由出生点地图写入百分比坐标，状态栏据此精确显示“你在这里”
 *  - 气血/法力值：由六维派生回满（initvar 占位 0，须在此初始化，否则血条蓝条为 0）
 *
 * @param stat_data 当前 mvu stat_data（会被就地修改）
 * @param 已选功法 玩家选定的功法名（draft store）
 * @param 已选神契 玩家选定的古神名（空串表示未选）
 */
export function inject捏角变量(stat_data: any, 已选功法: readonly string[], 已选神契: string): void {
  _.set(stat_data, '$flag.游戏模式', '沙盒模式');
  _.set(stat_data, '$flag.主角属性无上限', false);

  const 出身地 = String(_.get(stat_data, '主角.出身地', '')).trim();
  if (出身地 && 出身地 !== '待捏角') {
    _.set(stat_data, '世界.当前地点', 出身地);
  }

  // 1. 初始功法：先清空再装入，避免按钮一重试时残留累加
  stat_data.初始功法 = build初始功法(已选功法);

  // 1b. 功法树根节点：同步 seed 已选功法
  seedRootTechniques(stat_data, 已选功法);
  // 1c. 已学习被动功法的属性加成一次性写入真实六维；初始功法与功法树同名时按名称去重。
  结算已学习功法属性(stat_data);

  // 2. 古神列表：以本次捏角选择为准，清理旧版本 initvar/存档残留的默认神契
  const 古神列表 = _.get(stat_data, '古神列表') as Record<string, any> | undefined;
  if (古神列表) {
    for (const god of Object.values(古神列表)) {
      if (god && typeof god === 'object') {
        god.收服 = false;
        if (typeof god.沉沦值 === 'number') god.沉沦值 = 0;
      }
    }
    if (已选神契 && 古神列表[已选神契]) {
      古神列表[已选神契].收服 = true;
    }
  }
  // 3. 神契装备：与已选神契保持一致（StepDivineContract 里已设，此处兜底）
  _.set(stat_data, '主角.神契装备', 已选神契 ?? '');

  // 3b. 羁绊/在场：清理旧神契残留，再把已选神契写入 stat_data.羁绊（契缘标签读的是 羁绊）
  if (stat_data.羁绊) {
    for (const 神 of 神契列表) delete stat_data.羁绊[神.名称];
  }
  if (stat_data.在场) {
    for (const 神 of 神契列表) delete stat_data.在场[神.名称];
  }
  if (已选神契) {
    const 神契详情 = 神契列表.find(s => s.名称 === 已选神契);
    if (!stat_data.羁绊) stat_data.羁绊 = {};
    stat_data.羁绊[已选神契] = {
      境界: '古神',
      种族: '古神',
      性别: '未知',
      势力: '古神',
      关系: '神契同行',
      描述: 神契详情?.描述 ?? '',
      外貌: '',
      好感度: 50,
      洗脑值: 0,
      内心想法: 神契详情?.神契描述 ?? '',
      san值: 100,
      善恶值: 0,
      气血: 100,
      法力值: 0,
      六维: { 力道: 0, 体魄: 0, 身法: 0, 灵力: 0, 神识: 0, 根骨: 0 },
    };
  }

  // 4. 气血/法力值回满至六维派生上限
  const 六维 = _.get(stat_data, '主角.六维');
  _.set(stat_data, '主角.气血', deriveMaxHp(六维));
  _.set(stat_data, '主角.法力值', deriveMaxMp(六维));
}
